#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        getchar(); // consume newline after N
        char (*strs)[201] = malloc(N * 201 * sizeof(char));
        for (int i = 0; i < N; ++i) {
            if (!fgets(strs[i], 201, stdin)) strs[i][0] = '\0';
            strs[i][strcspn(strs[i], "\n")] = '\0'; // remove trailing newline
        }
        size_t minLen = strlen(strs[0]);
        for (int i = 1; i < N; ++i) {
            size_t len = strlen(strs[i]);
            if (len < minLen) minLen = len;
        }
        char prefix[201];
        size_t prefLen = 0;
        for (size_t i = 0; i < minLen; ++i) {
            char c = strs[0][i];
            int ok = 1;
            for (int j = 1; j < N; ++j) {
                if (strs[j][i] != c) { ok = 0; break; }
            }
            if (!ok) break;
            prefix[prefLen++] = c;
        }
        prefix[prefLen] = '\0';
        printf("%s\n", prefix);
        free(strs);
    }
    return 0;
}

